-- Migration 003: Security Fixes
-- Generated by security audit — 2026-03-24
-- ════════════════════════════════════════

-- ── [HIGH] Remove email from club_members — RGPD / data minimisation ──────
-- The dashboard only needs nickname (policy enforced in firebaseProvider.ts).
-- Gestors must not be able to read B2C player emails via the B2B dashboard.
-- Drop column entirely; if recovery is needed, restore from Firebase source.

ALTER TABLE club_members DROP COLUMN IF EXISTS email;

-- ── [MEDIUM] Fix maintenance_tickets foreign key types ────────────────────
-- court_id and gym_id were defined as text, bypassing referential integrity.
-- NOTE: these columns contain string IDs from the Firebase mobile app, so
-- a full uuid FK is not possible without a data migration.  At minimum we
-- add a CHECK constraint to enforce non-empty values.

ALTER TABLE maintenance_tickets
  ADD CONSTRAINT chk_maintenance_tickets_gym_id_nonempty
    CHECK (gym_id <> '');

ALTER TABLE maintenance_tickets
  ADD CONSTRAINT chk_maintenance_tickets_court_id_nonempty
    CHECK (court_id <> '');

-- ── [MEDIUM] Restrict maintenance_tickets UPDATE to prevent privilege esc. ─
-- Any gestor can currently UPDATE hoop_* fields (hoop_status, hoop_notes,
-- hoop_assigned_to) which are intended as internal Hoop Slam ops fields.
-- Drop the overly-broad update policy and replace with two scoped ones.

DROP POLICY IF EXISTS "gym_users_update_own_tickets" ON maintenance_tickets;

-- Gestors can only update non-hoop fields on their own gym tickets
CREATE POLICY "gestors_update_own_tickets" ON maintenance_tickets
  FOR UPDATE USING (
    auth.role() = 'authenticated'
    AND (select role from profiles where id = auth.uid()) IN ('gestor', 'staff')
    AND gym_id = ANY((select gym_ids from profiles where id = auth.uid()))
  )
  WITH CHECK (
    -- hoop_* fields must stay unchanged for gestor/staff
    hoop_status     IS NOT DISTINCT FROM (SELECT hoop_status     FROM maintenance_tickets WHERE id = maintenance_tickets.id)
    AND hoop_notes  IS NOT DISTINCT FROM (SELECT hoop_notes      FROM maintenance_tickets WHERE id = maintenance_tickets.id)
    AND hoop_assigned_to IS NOT DISTINCT FROM (SELECT hoop_assigned_to FROM maintenance_tickets WHERE id = maintenance_tickets.id)
  );

-- Admins can update everything (incl. hoop_* fields)
CREATE POLICY "admins_update_all_tickets" ON maintenance_tickets
  FOR UPDATE USING (
    auth.role() = 'authenticated'
    AND (select role from profiles where id = auth.uid()) = 'admin'
  );
